@js:
var url = String(result);
var idx1 = url.indexOf('book/');
var idx2 = url.indexOf('/', idx1 + 5);
var idx3 = url.indexOf('.html', idx2);
if(idx1 < 0 || idx2 < 0 || idx3 < 0){
  '章节URL格式错误: ' + url;
}else{
  var bookId = url.substring(idx1 + 5, idx2);
  var chapterId = url.substring(idx2 + 1, idx3);
  var dirid = source.get('dirid');
  if(!dirid){
    var bookInfo = java.ajax('https://5b78c.bqg353.xyz/api/book?id=' + bookId);
    var data = JSON.parse(bookInfo);
    dirid = data.dirid || bookId;
    source.put('dirid', dirid);
  }
  var apiUrl = 'https://5b78c.bqg353.xyz/api/chapter?id=' + dirid + '&chapterid=' + chapterId;
  try{
    var jsonStr = java.ajax(apiUrl);
    var data = JSON.parse(jsonStr);
    if(data && data.txt){
      var txt = data.txt.replace(/\n/g, '<br>');
      txt = txt.replace(/请收藏本站.*|手机版.*|bqg\d+\.com/gi, '');
      txt;
    }else{
      '获取正文失败';
    }
  }catch(e){
    'API调用失败: ' + e;
  }
}
